const { execSync } = require('child_process');
const os = require('os');

export async function execute(host = 'google.com', count = 4) {
  try {
    const pingCmd = os.platform() === 'win32' ? `ping -n ${count} ${host}` : `ping -c ${count} ${host}`;
    const output = execSync(pingCmd, { encoding: 'utf8', timeout: 10000 });
    return { success: true, output };
  } catch (err: any) {
    return { success: false, error: err.message, stderr: err.stderr?.toString() };
  }
}
